 * Fields: ai_tags, health_score, churn_risk, ai_best_contact_time, ai_communication_style
 */

const { Tag, Progress, Row, Col, Card, Space, Typography, Badge } = ctx.antd;
const { Text } = Typography;

// Theme detection
const algorithm = ctx.antdConfig?.theme?.algorithm;
const darkAlgo = ctx.antd.theme.darkAlgorithm;
const isDark = Array.isArray(algorithm)
  ? algorithm.some(fn => fn === darkAlgo)
  : algorithm === darkAlgo;
const T = ctx.themeToken || {};

// i18n
const t = (key, opts) => ctx.t(key, { ns: 'nb_crm', ...opts });

// ==================== Config ====================
const COLORS = {
  green: { stroke: '#10b981', text: '#10b981' },
  yellow: { stroke: '#f59e0b', text: '#f59e0b' },
  red: { stroke: '#ef4444', text: '#ef4444' },
};

// ==================== Components ====================

// Risk Badge Component
const RiskBadge = ({ riskColor, riskLabel }) => {
  const colorMap = {
    green: 'success',
    yellow: 'warning',
    red: 'error',
  };
  return (
    <Tag color={colorMap[riskColor] || 'default'} style={{ borderRadius: 6, fontWeight: 500 }}>
      {riskLabel}
    </Tag>
  );
};

// ==================== Main Component ====================
const AIProfile = () => {
  const record = ctx.record || ctx.popup?.record || {};

  // Parse AI tags
  let tags = record.ai_tags || [];
  if (typeof tags === 'string') {
    try {
      tags = JSON.parse(tags);
    } catch (e) {
      tags = tags.split(',').map(t => t.trim()).filter(Boolean);
    }
  }

  const healthScore = record.health_score || record.ai_health_score || 0;
  const churnRisk = record.churn_risk || record.ai_churn_risk || 0;
  const bestContactTime = record.ai_best_contact_time;
  const commStyle = record.ai_communication_style;

  const hasData = tags.length > 0 || healthScore > 0 || bestContactTime || commStyle;

  if (!hasData) {
    return (
      <Card style={{ position: 'relative' }}>
        <Badge.Ribbon text="🤖 AI Smart Profile" color="purple" style={{ top: -8 }}>
          <div style={{ textAlign: 'center', padding: 30, color: T.colorTextTertiary || '#9ca3af' }}>
            <div style={{ fontSize: 32, marginBottom: 8, opacity: 0.5 }}>🤖</div>
            <div>{t('AI analysis not available yet')}</div>
            <Text type="secondary" style={{ fontSize: 12, marginTop: 4, display: 'block' }}>{t('More customer data needed')}</Text>
          </div>
        </Badge.Ribbon>
      </Card>
    );
  }

  // Determine risk level
  let riskColor = 'green';
  let riskLabel = 'Low Risk';
  if (churnRisk >= 60) {
    riskColor = 'red';
    riskLabel = 'High Risk';
  } else if (churnRisk >= 30) {
    riskColor = 'yellow';
    riskLabel = 'Medium Risk';
  }

  // Get health color
  let healthColor = 'green';
  if (healthScore < 40) {
    healthColor = 'red';
  } else if (healthScore < 70) {
    healthColor = 'yellow';
  }

  return (
    <Card style={{ position: 'relative' }}>
      <Badge.Ribbon text="🤖 AI Smart Profile" color="purple" style={{ top: -8 }}>
        <div style={{ paddingTop: 8 }}>
          {/* AI Tags */}
          {tags.length > 0 && (
            <Space wrap style={{ marginBottom: 20 }}>
              {tags.map((tag, index) => {
                const tagText = typeof tag === 'object' ? tag.name || tag.label : tag;
                const isHighlight = tagText.toLowerCase().includes('high value') ||
                                   tagText.toLowerCase().includes('vip');
                return (
                  <Tag
                    key={index}
                    color={isHighlight ? 'green' : 'purple'}
                    style={{ borderRadius: 20, padding: '6px 14px', fontSize: 13 }}
                  >
                    #{tagText}
                  </Tag>
                );
              })}
            </Space>
          )}

          {/* Health Score & Churn Risk */}
          <Row gutter={16} style={{ marginBottom: 20 }}>
            <Col span={12}>
              <Card size="small" style={{ background: T.colorBgLayout || '#f9fafb', textAlign: 'center' }}>
                <Text type="secondary" style={{ fontSize: 12, display: 'block', marginBottom: 8 }}>{t('Health Score')}</Text>
                <Progress
                  type="circle"
                  percent={healthScore}
                  size={80}
                  strokeColor={COLORS[healthColor].stroke}
                  format={(percent) => (
                    <span style={{ color: COLORS[healthColor].text, fontWeight: 700, fontSize: 20 }}>
                      {percent}
                    </span>
                  )}
                />
              </Card>
            </Col>
            <Col span={12}>
              <Card size="small" style={{ background: T.colorBgLayout || '#f9fafb', textAlign: 'center' }}>
                <Text type="secondary" style={{ fontSize: 12, display: 'block', marginBottom: 8 }}>{t('Churn Risk')}</Text>
                <Progress
                  type="circle"
                  percent={churnRisk}
                  size={80}
                  strokeColor={COLORS[riskColor].stroke}
                  format={(percent) => (
                    <span style={{ color: COLORS[riskColor].text, fontWeight: 700, fontSize: 20 }}>
                      {percent}
                    </span>
                  )}
                />
                <div style={{ marginTop: 8 }}>
                  <RiskBadge riskColor={riskColor} riskLabel={riskLabel} />
                </div>
              </Card>
            </Col>
          </Row>

          {/* AI Suggestions */}
          {(bestContactTime || commStyle) && (
            <div style={{ borderTop: `1px solid ${T.colorBorderSecondary || '#e5e7eb'}`, paddingTop: 20 }}>
              {bestContactTime && (
                <Card
                  size="small"
                  style={{ marginBottom: 10, borderLeft: '3px solid #6366f1', background: T.colorBgLayout || '#f9fafb' }}
                  bodyStyle={{ padding: 12 }}
                >
                  <Space>
                    <Badge
                      count="⏰"
                      style={{ backgroundColor: 'rgba(99, 102, 241, 0.2)', color: '#6366f1' }}
                    />
                    <div>
                      <Text strong style={{ fontSize: 13, display: 'block', marginBottom: 4 }}>{t('Best Contact Time')}</Text>
                      <Text type="secondary" style={{ fontSize: 12 }}>{bestContactTime}</Text>
                    </div>
                  </Space>
                </Card>
              )}
              {commStyle && (
                <Card
                  size="small"
                  style={{ borderLeft: '3px solid #6366f1', background: T.colorBgLayout || '#f9fafb' }}
                  bodyStyle={{ padding: 12 }}
                >
                  <Space>
                    <Badge
                      count="💬"
                      style={{ backgroundColor: 'rgba(99, 102, 241, 0.2)', color: '#6366f1' }}
                    />
                    <div>
                      <Text strong style={{ fontSize: 13, display: 'block', marginBottom: 4 }}>{t('Communication Strategy')}</Text>
                      <Text type="secondary" style={{ fontSize: 12 }}>{commStyle}</Text>
                    </div>
                  </Space>
                </Card>
              )}
            </div>
          )}
        </div>
      </Badge.Ribbon>
    </Card>
  );
};

ctx.render(<AIProfile />);

/**
 * Contact Row Column - Customer 360
 *
 * Displays a contact row in a business style.
 * Shows: Name, Title, Role Tag
 * Clickable to open contact detail popup.
 *
 * Table: nb_crm_contacts (related to customer)
 * Fields: name, title, role, is_primary
 */

// i18n
const t = (key, opts) => ctx.t(key, { ns: 'nb_crm', ...opts });


const { Space, Tag, Typography } = ctx.antd;
const { Text } = Typography;

// Role tag configuration
const ROLE_TAGS = {
  decision_maker: { label: t('Decision Maker'), color: 'orange' },
  influencer: { label: t('Influencer'), color: 'green' },
  technical_evaluator: { label: t('Technical'), color: 'blue' },
  procurement: { label: t('Procurement'), color: 'cyan' },
  executor: { label: t('Executor'), color: 'default' },
};

// Configure popup UID
const VIEW_CONFIG = {
  contactDetailPopup: 'zxsog8ixwmu',
};

const ContactRow = () => {
  const record = ctx.record || {};
  const name = record.name || 'Unknown';
  const title = record.title || '';
  const role = record.role?.toLowerCase()?.replace(/\s+/g, '_') || '';
  const isPrimary = record.is_primary;

  const roleTag = ROLE_TAGS[role];

  const handleClick = async () => {
    if (!ctx.openView || !record.id) return;

    const viewUid = VIEW_CONFIG.contactDetailPopup;
    if (!viewUid || viewUid.startsWith('REPLACE_WITH')) {
      console.warn('Configure VIEW_CONFIG.contactDetailPopup');
      return;
    }

    try {
      await ctx.openView(viewUid, {
        mode: 'drawer',
        size: 'medium',
        filterByTk: record.id,
      });
    } catch (error) {
      console.error('Failed to open contact detail:', error);
    }
  };

  return (
    <div
      onClick={handleClick}
      style={{
        padding: '8px 0',
        cursor: 'pointer',
      }}
    >
      <Space align="center" style={{ width: '100%' }}>
        <div style={{ flex: 1, minWidth: 0 }}>
          <Space size={6}>
            <Text strong style={{ fontSize: 14 }}>{name}</Text>
            {isPrimary && <Tag color="gold">{t('Primary')}</Tag>}
          </Space>
          {title && (
            <Text type="secondary" style={{ fontSize: 12, display: 'block', marginTop: 2 }}>
              {title}
            </Text>
          )}
        </div>
        {roleTag && <Tag color={roleTag.color}>{roleTag.label}</Tag>}
      </Space>
    </div>
  );
};

ctx.render(<ContactRow />);

/**
 * Opportunity Row Column - Customer 360
 *
 * Displays an opportunity row in a business style.
 * Shows: Name, Stage Tag, Amount, Win Probability
 * Clickable to open opportunity detail popup.
 *
 * Table: nb_crm_opportunities (related to customer)
 * Fields: name, stage, amount, win_probability, currency
 * Currency symbols loaded from: nb_cbo_currencies
 */

const { Space, Tag, Typography, Spin } = ctx.antd;
const { Text } = Typography;
const { useState, useEffect } = ctx.React;

// Theme detection
const algorithm = ctx.antdConfig?.theme?.algorithm;
const darkAlgo = ctx.antd.theme.darkAlgorithm;
const isDark = Array.isArray(algorithm)
  ? algorithm.some(fn => fn === darkAlgo)
  : algorithm === darkAlgo;
const T = ctx.themeToken || {};

// i18n
const t = (key, opts) => ctx.t(key, { ns: 'nb_crm', ...opts });

// Stage configurations
const STAGE_CONFIG = {
  qualification: { label: t('Qualification'), color: 'default' },
  needs_analysis: { label: t('Needs Analysis'), color: 'processing' },
  proposal: { label: t('Proposal'), color: 'processing' },
  negotiation: { label: t('Negotiation'), color: 'warning' },
  closed_won: { label: t('Won'), color: 'success' },
  won: { label: t('Won'), color: 'success' },
  closed_lost: { label: t('Lost'), color: 'error' },
  lost: { label: t('Lost'), color: 'error' },
};

// Configure popup UID
const VIEW_CONFIG = {
  opportunityDetailPopup: 'xzuvlcsgar6',
};

// Currency cache (shared across renders)
let currencyCache = null;
let currencyLoading = false;
let currencyLoadPromise = null;

const loadCurrencies = async () => {
  if (currencyCache) return currencyCache;
  if (currencyLoading) return currencyLoadPromise;

  currencyLoading = true;
  currencyLoadPromise = (async () => {
    try {
      const res = await ctx.api.request({
        url: 'nb_cbo_currencies:list',
        method: 'GET',
        params: { pageSize: 100, filter: { is_active: true } },
      });
      const list = res?.data?.data || [];
      currencyCache = {};
      list.forEach(c => {
        currencyCache[c.code] = c.symbol || c.code;
      });
      return currencyCache;
    } catch (e) {
      console.error('Failed to load currencies:', e);
      // Fallback
      return { CNY: '¥', USD: '$', EUR: '€', GBP: '£' };
    } finally {
      currencyLoading = false;
    }
  })();
  return currencyLoadPromise;
};

const formatAmount = (amount, currency = 'CNY', currencyMap = {}) => {
  const symbol = currencyMap[currency] || currency;
  if (amount >= 1000000) {
    return `${symbol}${(amount / 1000000).toFixed(1)}M`;
  }
  if (amount >= 1000) {
    return `${symbol}${(amount / 1000).toFixed(0)}K`;
  }
  return `${symbol}${amount?.toLocaleString() || 0}`;
};

const OpportunityRow = () => {
  const record = ctx.record || {};
  const name = record.name || 'Untitled Opportunity';
  const stage = record.stage || '';
  const amount = record.amount || record.expected_amount || 0;
  const currency = record.currency || 'CNY';
  const winProb = record.win_probability || record.probability || 0;

  const [currencyMap, setCurrencyMap] = useState(currencyCache || {});
  const [loading, setLoading] = useState(!currencyCache);

  useEffect(() => {
    if (!currencyCache) {
      loadCurrencies().then(map => {
        setCurrencyMap(map);
        setLoading(false);
      });
    }
  }, []);

  const stageConfig = STAGE_CONFIG[stage] || { label: stage, color: 'default' };

  const handleClick = async () => {
    if (!ctx.openView || !record.id) return;

    const viewUid = VIEW_CONFIG.opportunityDetailPopup;
    if (!viewUid || viewUid.startsWith('REPLACE_WITH')) {
      console.warn('Configure VIEW_CONFIG.opportunityDetailPopup');
      return;
    }

    try {
      await ctx.openView(viewUid, {
        mode: 'drawer',
        size: 'large',
        filterByTk: record.id,
      });
    } catch (error) {
      console.error('Failed to open opportunity detail:', error);
    }
  };

  return (
    <div
      onClick={handleClick}
      style={{
        padding: '12px 0',
        borderBottom: `1px solid ${T.colorBorderSecondary || '#f0f0f0'}`,
        cursor: 'pointer',
      }}
    >
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' }}>
        <div style={{ flex: 1, minWidth: 0 }}>
          <Text strong ellipsis style={{ fontSize: 14, display: 'block', marginBottom: 6 }}>
            {name}
          </Text>
          <Space size={8}>
            <Tag color={stageConfig.color}>{stageConfig.label}</Tag>
            <Text type="secondary" style={{ fontSize: 12 }}>Win {winProb}%</Text>
          </Space>
        </div>
        <Text strong style={{ fontSize: 14, flexShrink: 0 }}>
          {formatAmount(amount, currency, currencyMap)}
        </Text>
      </div>
    </div>
  );
};

ctx.render(<OpportunityRow />);

