/**
 * Customer Name Duplicate Check Field
 *
 * A form field component for customer name input with real-time duplicate detection.
 * Uses Antd Input with status and Typography for warnings.
 *
 * Features:
 * - Debounced duplicate checking (500ms)
 * - Compact inline warning display
 * - Shows exact matches in red, similar matches in yellow
 * - Max 3 items displayed, then "+N more"
 * - Bidirectional binding with form value
 *
 * Table: nb_crm_customers
 * Field: name (string, required, unique)
 */

// i18n
const t = (key, opts) => ctx.t(key, { ns: 'nb_crm', ...opts });


const { useState, useEffect, useCallback } = ctx.React;
const { Input, Spin, Typography, Space } = ctx.antd;
const { Text } = Typography;

// ==================== Configuration ====================
const TABLE_NAME = 'nb_crm_customers';
const FIELD_NAME = 'name';
const DEBOUNCE_DELAY = 500;
const MAX_DISPLAY_MATCHES = 3;

// ==================== Utility Functions ====================

/**
 * Debounce hook
 */
function useDebounce(value, delay) {
  const [debouncedValue, setDebouncedValue] = useState(value);

  useEffect(() => {
    const timer = setTimeout(() => {
      setDebouncedValue(value);
    }, delay);

    return () => {
      clearTimeout(timer);
    };
  }, [value, delay]);

  return debouncedValue;
}

/**
 * Check if it's an exact match (case-insensitive, trimmed)
 */
function isExactMatch(input, target) {
  if (!input || !target) return false;
  return input.trim().toLowerCase() === target.trim().toLowerCase();
}

/**
 * Format matches for display: "Item1, Item2, +N more"
 */
function formatMatchList(matches, fieldName, maxItems) {
  const names = matches.slice(0, maxItems).map(m => m[fieldName]);
  const remaining = matches.length - maxItems;

  if (remaining > 0) {
    return names.join(', ') + t(', +{{remaining}} more', { remaining: remaining });
  }
  return names.join(', ');
}

// ==================== Main Component ====================
const CustomerNameCheckField = () => {
  const [value, setValue] = useState(() => ctx.getValue?.() || '');
  const [checking, setChecking] = useState(false);
  const [matches, setMatches] = useState([]);
  const [hasChecked, setHasChecked] = useState(false);

  const debouncedValue = useDebounce(value, DEBOUNCE_DELAY);
  const currentRecordId = ctx.record?.id;

  /**
   * Perform duplicate check using resource API
   */
  const checkDuplicate = useCallback(async (searchText) => {
    if (!searchText || searchText.trim().length === 0) {
      setMatches([]);
      setHasChecked(false);
      return;
    }

    setChecking(true);

    try {
      const result = await ctx.api.request({
        url: `${TABLE_NAME}:list`,
        method: 'get',
        params: {
          filter: {
            [FIELD_NAME]: { $includes: searchText.trim() }
          },
          pageSize: 10,
          fields: ['id', 'name']
        }
      });

      const data = result?.data?.data || [];

      // Exclude current record in edit mode
      const filteredData = currentRecordId
        ? data.filter(item => item.id !== currentRecordId)
        : data;

      // Mark exact and similar matches
      const processedMatches = filteredData.map(item => ({
        ...item,
        isExact: isExactMatch(searchText, item[FIELD_NAME]),
      }));

      // Sort: exact matches first
      processedMatches.sort((a, b) => {
        if (a.isExact && !b.isExact) return -1;
        if (!a.isExact && b.isExact) return 1;
        return 0;
      });

      setMatches(processedMatches);
      setHasChecked(true);

    } catch (err) {
      console.error('Duplicate check failed:', err);
      setMatches([]);
      setHasChecked(true);
    } finally {
      setChecking(false);
    }
  }, [currentRecordId]);

  /**
   * Watch debounced value changes and trigger check
   */
  useEffect(() => {
    checkDuplicate(debouncedValue);
  }, [debouncedValue, checkDuplicate]);

  /**
   * Sync to form (bidirectional binding)
   */
  useEffect(() => {
    ctx.setValue?.(value);
  }, [value]);

  /**
   * Watch for external value changes
   */
  useEffect(() => {
    const handler = (ev) => {
      const next = ev?.detail ?? '';
      setValue(next);
    };
    ctx.element?.addEventListener('js-field:value-change', handler);
    return () => ctx.element?.removeEventListener('js-field:value-change', handler);
  }, []);

  /**
   * Handle input change
   */
  const handleChange = (e) => {
    setValue(e.target.value);
  };

  /**
   * Get input status for styling
   */
  const getInputStatus = () => {
    if (checking || !hasChecked || matches.length === 0) return '';
    const hasExact = matches.some(m => m.isExact);
    return hasExact ? 'error' : 'warning';
  };

  /**
   * Render compact warning text
   */
  const renderWarning = () => {
    if (checking || !hasChecked || !value?.trim() || matches.length === 0) {
      return null;
    }

    const hasExact = matches.some(m => m.isExact);
    const exactMatches = matches.filter(m => m.isExact);
    const similarMatches = matches.filter(m => !m.isExact);

    // Exact match - red warning
    if (hasExact) {
      const displayText = formatMatchList(exactMatches, FIELD_NAME, MAX_DISPLAY_MATCHES);
      return (
        <Text type="danger" style={{ fontSize: 12, marginTop: 4, display: 'block' }}>
          Exists: {displayText}
        </Text>
      );
    }

    // Similar matches only - yellow warning
    const displayText = formatMatchList(similarMatches, FIELD_NAME, MAX_DISPLAY_MATCHES);
    return (
      <Text type="warning" style={{ fontSize: 12, marginTop: 4, display: 'block' }}>
        Similar: {displayText}
      </Text>
    );
  };

  return (
    <div style={{ width: '100%' }}>
      <Input
        style={{ width: '100%' }}
        value={value}
        onChange={handleChange}
        placeholder={t('Enter customer name')}
        status={getInputStatus()}
        suffix={checking ? <Spin size="small" /> : null}
        allowClear
      />
      {renderWarning()}
    </div>
  );
};

